import {
  CSSProperties,
  forwardRef,
  JSXElementConstructor,
  MouseEvent,
  ReactElement,
  ReactNode,
} from 'react';
import { clsx } from 'clsx';
import { tw } from '@utils/useTailwind';
import { ButtonLoadingIcon } from './components/ButtonLoadingIcon';
import {
  BASE_CLASSES,
  IS_ACTIVE_CLASSES,
  IS_DISABLED_CLASSES,
  SIZE_CLASSES,
  VARIANT_CLASSES,
  VARIANT_SIZE_CLASSES,
} from './constants';

// TODO: migrate remaining variants from src/ui/theme/components/button/variants
type MigratedVariants =
  | 'donationAmount'
  | 'icon'
  | 'link'
  | 'menuItem'
  | 'primary'
  | 'secondary'
  | 'secondaryWhite'
  | 'tertiary'
  | 'tertiaryWhite'
  | 'unstyled';

export type ButtonVariant =
  | MigratedVariants
  | 'colorPicker'
  | 'donationAmount'
  | 'nav'
  | 'navAdmin'
  | 'navQa'
  | 'navSandbox'
  | 'secondaryNav'
  | 'secondaryNavAdmin'
  | 'secondaryNavQa'
  | 'secondaryNavSandbox'
  | 'primaryCellAction'
  | 'secondaryCellAction'
  | 'secondaryDrawerAction'
  | 'text'
  | 'toggle'
  | 'danger'
  | 'submit'
  | 'defaultSubmit';

export type SizeVariant = 'sm' | 'md' | 'lg';

export type ButtonProps = {
  children?: ReactNode;
  className?: string;
  form?: string;
  icon?: ReactElement<unknown, string | JSXElementConstructor<unknown>>;
  iconClassName?: string;
  iconSpacing?: 1 | 2;
  isActive?: boolean;
  isDestructive?: boolean;
  isDisabled?: boolean;
  isLoading?: boolean;
  leftIcon?: ReactElement<unknown, string | JSXElementConstructor<unknown>>;
  onClick?: (e: MouseEvent<HTMLButtonElement>) => unknown;
  rightIcon?: ReactElement<unknown, string | JSXElementConstructor<unknown>>;
  size?: SizeVariant;
  style?:
    | CSSProperties
    | {
        [key: string]: string;
      };
  tabIndex?: number;
  type?: 'reset' | 'button' | 'submit';
  variant?: MigratedVariants;
};

const getSizeClasses = (size: Partial<SizeVariant>, variant: MigratedVariants) => {
  return clsx(SIZE_CLASSES[size], {
    'min-w-[3rem] pe-2 ps-2':
      (size === 'sm' && variant !== 'icon') ||
      ((size === 'md' || size === 'lg') && (variant === 'tertiary' || variant === 'tertiaryWhite')),
    'min-w-[3rem] pe-3 ps-3': (size === 'md' || size === 'lg') && variant !== 'icon',
    'pe-2 ps-2': size === 'md' && variant === 'icon',
    'pe-3 ps-3': size === 'lg' && variant === 'icon',
  });
};

// forwardRef is required for Popovers on Buttons
export const Button = forwardRef<HTMLButtonElement, ButtonProps>((props, ref) => {
  const {
    children,
    className,
    form,
    icon,
    iconClassName,
    iconSpacing = 1,
    isActive,
    isDisabled = false,
    isLoading,
    leftIcon,
    onClick,
    rightIcon,
    size = 'md',
    style,
    tabIndex = 0,
    type = 'button',
    variant = 'primary',
    ...rest
  } = props;

  const buttonType = form ? 'submit' : type;

  const buttonClasses =
    variant !== 'unstyled'
      ? clsx(
          BASE_CLASSES,
          getSizeClasses(size, variant),
          isActive && IS_ACTIVE_CLASSES[variant],
          isDisabled && IS_DISABLED_CLASSES[variant],
          isLoading && tw`[&>*:not(:first-child)]:invisible`,
          VARIANT_CLASSES[variant],
          VARIANT_SIZE_CLASSES?.[variant]?.[size],
          className && className
        )
      : clsx(className && className);
  const buttonIconClasses = clsx(
    tw`inline-flex h-[15px] w-[15px] shrink-0 self-center`,
    iconClassName && iconClassName,
    leftIcon && (iconSpacing === 2 ? 'me-2' : 'me-1'),
    rightIcon && (iconSpacing === 2 ? 'ms-2' : 'ms-1')
  );

  return (
    <button
      className={buttonClasses}
      disabled={isDisabled || isLoading}
      form={form}
      onClick={(e) => onClick?.(e)}
      ref={ref}
      style={style}
      tabIndex={tabIndex}
      // eslint-disable-next-line react/button-has-type
      type={buttonType}
      {...rest}
    >
      {isLoading && (
        <ButtonLoadingIcon isActive={isActive} isDisabled={isDisabled} variant={variant} />
      )}

      {leftIcon && <span className={buttonIconClasses}>{leftIcon}</span>}
      {variant === 'icon' && icon && icon}
      {variant !== 'icon' && children && (isLoading ? <span>{children}</span> : children)}
      {rightIcon && <span className={buttonIconClasses}>{rightIcon}</span>}
    </button>
  );
});
